# Define functions
ggd.qqplot = function(pvector, main=NULL, ...) {
    o = -log10(sort(pvector,decreasing=F))
    e = -log10( 1:length(o)/length(o) )
    plot(e,o,pch=19,cex=1, main=main, ...,
		 xlab=expression(Expected~~(-log[10](italic(p)))),
		 ylab=expression(Observed~~(-log[10](italic(p)))),
		 xlim=c(0,max(e)), ylim=c(0,max(o)))
    abline(0,1, col="red")
}

pvalues_above_qqline = function(pvector) {
  # Clean p-values
  valid_idx = which(!is.na(pvector) & pvector > 0 & pvector <= 1)
  p_clean = pvector[valid_idx]
  n = length(p_clean)
  
  # Sort and compute observed/expected
  sorted_idx = order(p_clean)
  sorted_p = p_clean[sorted_idx]
  observed = -log10(sorted_p)
  expected = -log10(ppoints(n))
  
  # Identify where observed > expected
  above = observed > expected
  
  # Filter and return only those above the line
  return(data.frame(
    original_index = valid_idx[sorted_idx][above],
    p_value = sorted_p[above],
    observed = observed[above],
    expected = expected[above]
  ))
}

