# Generate QQ-Plot
ggd.qqplot(PValues, "QQ-plot, MLMA-LOCO")

# Generate pvalues table
observed_pvalues= -log10(sort(PValues,decreasing=F))
expected_pvalues= -log10(1:length(observed_pvalues)/length(observed_pvalues))

# Check points above expected line function
pvalues_above_expected<-pvalues_above_qqline(PValues)
write.csv(pvalues_above_expected, "data/pvalues_above_expected.csv", row.names = FALSE)

# Generate Manhattan Plot
ntests = 800
